+//! Metal Performance Shaders Graph (MPSGraph) Bindings
+//!
+//! MPSGraph provides automatic routing to Neural Engine (ANE) for optimal performance.
+//! Unlike manual Metal kernels, MPSGraph analyzes the computation graph and automatically
+//! dispatches to GPU, CPU, or ANE based on operation characteristics.
+//!
+//! Key advantages:
+//! - Automatic ANE routing (no manual heuristics)
+//! - Graph-level optimizations (fusion, memory planning)
+//! - Much lower overhead than manual Metal dispatch (~0.1ms vs ~2-3ms)
+//! - Operator fusion (matmul + activation combined)
+//!
+//! References:
+//! - https://developer.apple.com/documentation/metalperformanceshadersgraph
+//! - https://developer.apple.com/videos/play/wwdc2021/10152/
+
+const std = @import("std");
+const builtin = @import("builtin");
+const objc = @import("objc.zig");
+
+// =============================================================================
+// MPSGraph Type Aliases
+// =============================================================================
+
+pub const MPSGraph = *anyopaque;
+pub const MPSGraphTensor = *anyopaque;
+pub const MPSGraphTensorData = *anyopaque;
+pub const MPSGraphExecutable = *anyopaque;
+pub const MPSGraphExecutionDescriptor = *anyopaque;
+pub const MPSGraphDevice = *anyopaque;
+pub const MPSNDArray = *anyopaque;
+pub const MPSNDArrayDescriptor = *anyopaque;
+pub const MPSDataType = u32;
+pub const MPSShape = *anyopaque;
+
+// =============================================================================
+// MPSDataType Enum Values
+// =============================================================================
+
+pub const MPSDataTypeFloat32: MPSDataType = 268435472; // 0x10000010
+pub const MPSDataTypeFloat16: MPSDataType = 268435488; // 0x10000020
+pub const MPSDataTypeBFloat16: MPSDataType = 268435489; // 0x10000021
+pub const MPSDataTypeInt8: MPSDataType = 262144;       // 0x00040000
+pub const MPSDataTypeInt32: MPSDataType = 268435460;   // 0x10000004
+
+// =============================================================================
+// Objective-C Runtime Helpers
+// =============================================================================
+
+const c = if (builtin.os.tag == .macos) struct {
+    extern "objc" fn objc_msgSend() void;
+    extern "objc" fn sel_registerName(name: [*:0]const u8) *anyopaque;
+    extern "objc" fn objc_getClass(name: [*:0]const u8) ?*anyopaque;
+} else struct {};
+
+fn sel(name: [*:0]const u8) *anyopaque {
+    return c.sel_registerName(name);
+}
+
+fn msgSend0(comptime T: type) *const fn (*anyopaque, *anyopaque) callconv(.C) T {
+    return @ptrCast(&c.objc_msgSend);
+}
+
+fn msgSend1(comptime T: type, comptime A1: type) *const fn (*anyopaque, *anyopaque, A1) callconv(.C) T {
+    return @ptrCast(&c.objc_msgSend);
+}
+
+fn msgSend2(comptime T: type, comptime A1: type, comptime A2: type) *const fn (*anyopaque, *anyopaque, A1, A2) callconv(.C) T {
+    return @ptrCast(&c.objc_msgSend);
+}
+
+fn msgSend3(comptime T: type, comptime A1: type, comptime A2: type, comptime A3: type) *const fn (*anyopaque, *anyopaque, A1, A2, A3) callconv(.C) T {
+    return @ptrCast(&c.objc_msgSend);
+}
+
+// =============================================================================
+// MPSGraph Creation and Management
+// =============================================================================
+
+/// Create a new MPSGraph
+/// Returns: MPSGraph instance
+pub fn createGraph() MPSGraph {
+    const MPSGraphClass = c.objc_getClass("MPSGraph") orelse unreachable;
+    const graph = msgSend0(MPSGraph)(MPSGraphClass, sel("new"));
+    return graph;
+}
+
+/// Release an MPSGraph object
+pub fn releaseGraph(graph: MPSGraph) void {
+    _ = msgSend0(void)(graph, sel("release"));
+}
+
+// =============================================================================
+// MPSGraph Tensor Creation (Placeholders)
+// =============================================================================
+
+/// Create a placeholder tensor
+/// shape: [M, K] for example
+/// dataType: MPSDataTypeBFloat16, etc.
+pub fn createPlaceholder(
+    graph: MPSGraph,
+    shape: []const u32,
+    dataType: MPSDataType,
+    name: []const u8,
+) MPSGraphTensor {
+    // Convert shape to NSArray
+    const shape_array = createNSArrayFromU32(shape);
+    defer objc.release(shape_array);
+
+    // Convert name to NSString
+    const ns_name = objc.createNSString(name) orelse unreachable;
+    defer objc.release(ns_name);
+
+    // Call: placeholderWithShape:dataType:name:
+    const tensor = msgSend3(
+        MPSGraphTensor,
+        *anyopaque,
+        MPSDataType,
+        *anyopaque,
+    )(graph, sel("placeholderWithShape:dataType:name:"), shape_array, dataType, ns_name);
+
+    return tensor;
+}
+
+// =============================================================================
+// MPSGraph Operations
+// =============================================================================
+
+/// Matrix multiplication: C = A × B
+/// A: [M, K]
+/// B: [K, N]
+/// Returns: [M, N]
+pub fn matrixMultiplication(
+    graph: MPSGraph,
+    primaryTensor: MPSGraphTensor,    // A
+    secondaryTensor: MPSGraphTensor,  // B
+    name: []const u8,
+) MPSGraphTensor {
+    const ns_name = objc.createNSString(name) orelse unreachable;
+    defer objc.release(ns_name);
+
+    // Call: matrixMultiplicationWithPrimaryTensor:secondaryTensor:name:
+    const result = msgSend3(
+        MPSGraphTensor,
+        MPSGraphTensor,
+        MPSGraphTensor,
+        *anyopaque,
+    )(graph, sel("matrixMultiplicationWithPrimaryTensor:secondaryTensor:name:"),
+      primaryTensor, secondaryTensor, ns_name);
+
+    return result;
+}
+
+/// ReLU activation
+pub fn relu(graph: MPSGraph, tensor: MPSGraphTensor, name: []const u8) MPSGraphTensor {
+    const ns_name = objc.createNSString(name) orelse unreachable;
+    defer objc.release(ns_name);
+
+    const result = msgSend2(
+        MPSGraphTensor,
+        MPSGraphTensor,
+        *anyopaque,
+    )(graph, sel("reLUWithTensor:name:"), tensor, ns_name);
+
+    return result;
+}
+
+/// Addition: A + B
+pub fn addition(
+    graph: MPSGraph,
+    primaryTensor: MPSGraphTensor,
+    secondaryTensor: MPSGraphTensor,
+    name: []const u8,
+) MPSGraphTensor {
+    const ns_name = objc.createNSString(name) orelse unreachable;
+    defer objc.release(ns_name);
+
+    const result = msgSend3(
+        MPSGraphTensor,
+        MPSGraphTensor,
+        MPSGraphTensor,
+        *anyopaque,
+    )(graph, sel("additionWithPrimaryTensor:secondaryTensor:name:"),
+      primaryTensor, secondaryTensor, ns_name);
+
+    return result;
+}
+
+// =============================================================================
+// MPSGraph Execution
+// =============================================================================
+
+/// Create execution descriptor
+pub fn createExecutionDescriptor() MPSGraphExecutionDescriptor {
+    const DescriptorClass = c.objc_getClass("MPSGraphExecutionDescriptor") orelse unreachable;
+    const descriptor = msgSend0(MPSGraphExecutionDescriptor)(DescriptorClass, sel("new"));
+    return descriptor;
+}
+
+/// Run graph synchronously
+/// feeds: Dictionary mapping placeholder tensors to input data
+/// targetTensors: Array of output tensors to compute
+/// Returns: Dictionary mapping output tensors to result data
+pub fn runSync(
+    graph: MPSGraph,
+    feeds: *anyopaque,  // NSDictionary
+    targetTensors: *anyopaque,  // NSArray
+    executionDescriptor: ?MPSGraphExecutionDescriptor,
+) *anyopaque {
+    const desc = executionDescriptor orelse createExecutionDescriptor();
+
+    // Call: runWithMTLCommandQueue:feeds:targetTensors:targetOperations:executionDescriptor:
+    const results = msgSend3(
+        *anyopaque,
+        *anyopaque,
+        *anyopaque,
+        MPSGraphExecutionDescriptor,
+    )(graph, sel("runWithFeeds:targetTensors:executionDescriptor:"),
+      feeds, targetTensors, desc);
+
+    return results;
+}
+
+// =============================================================================
+// Helper Functions
+// =============================================================================
+
+/// Create NSArray from u32 slice (for shape)
+fn createNSArrayFromU32(values: []const u32) *anyopaque {
+    const NSArrayClass = c.objc_getClass("NSMutableArray") orelse unreachable;
+    const array = msgSend0(*anyopaque)(NSArrayClass, sel("new"));
+
+    for (values) |val| {
+        // Create NSNumber
+        const NSNumberClass = c.objc_getClass("NSNumber") orelse unreachable;
+        const num = msgSend1(*anyopaque, u32)(NSNumberClass, sel("numberWithUnsignedInt:"), val);
+
+        // Add to array
+        _ = msgSend1(void, *anyopaque)(array, sel("addObject:"), num);
+    }
+
+    return array;
+}
+
+/// Create NSDictionary from two arrays (keys and values)
+pub fn createNSDictionary(keys: []*anyopaque, values: []*anyopaque) *anyopaque {
+    std.debug.assert(keys.len == values.len);
+
+    const NSDictionaryClass = c.objc_getClass("NSDictionary") orelse unreachable;
+    const dict = msgSend2(
+        *anyopaque,
+        [*]*anyopaque,
+        usize,
+    )(NSDictionaryClass, sel("dictionaryWithObjects:forKeys:count:"),
+      values.ptr, keys.len);
+
+    return dict;
+}
+
+// =============================================================================
+// MPSNDArray - Tensor Data Container
+// =============================================================================
+
+/// Create MPSNDArray descriptor
+pub fn createNDArrayDescriptor(
+    dataType: MPSDataType,
+    shape: []const u32,
+) MPSNDArrayDescriptor {
+    const shape_array = createNSArrayFromU32(shape);
+    defer objc.release(shape_array);
+
+    const DescriptorClass = c.objc_getClass("MPSNDArrayDescriptor") orelse unreachable;
+    const descriptor = msgSend2(
+        MPSNDArrayDescriptor,
+        MPSDataType,
+        *anyopaque,
+    )(DescriptorClass, sel("descriptorWithDataType:shape:"), dataType, shape_array);
+
+    return descriptor;
+}
+
+/// Create MPSNDArray from buffer
+pub fn createNDArray(
+    device: objc.MTLDevice,
+    descriptor: MPSNDArrayDescriptor,
+    buffer: objc.MTLBuffer,
+) MPSNDArray {
+    const NDArrayClass = c.objc_getClass("MPSNDArray") orelse unreachable;
+    const array = msgSend2(
+        MPSNDArray,
+        objc.MTLBuffer,
+        MPSNDArrayDescriptor,
+    )(NDArrayClass, sel("initWithBuffer:descriptor:"), buffer, descriptor);
+
+    _ = device; // Device might be needed in future
+    return array;
+}
+
+/// Get MPSGraphTensorData from MPSNDArray
+pub fn getTensorData(ndarray: MPSNDArray) MPSGraphTensorData {
+    // MPSNDArray conforms to MPSGraphTensorData protocol
+    return @ptrCast(ndarray);
+}

